199: // hasPendingSnapshot returns if there is pending snapshot waiting for applying.
200: func (l *raftLog) hasPendingSnapshot() bool {
201: 	return l.unstable.snapshot != nil && !IsEmptySnap(*l.unstable.snapshot)
202: }
